export class TextDB{static API_URL="https://textdb.dev/api/data";constructor(t){this.key=t||this.randomKey(3)}static read=async t=>new TextDB(t).read();static write=async(t,e)=>new TextDB(t).write(e);static url=t=>new TextDB(t).url();static randomKey=()=>(new TextDB).randomKey();static getReadOnlyKey=async t=>new TextDB(t).getReadOnlyKey();static getReadOnlyLink=async t=>new TextDB(t).getReadOnlyLink();getReadOnlyLink=async()=>`${TextDB.API_URL}/${await this.getReadOnlyKey()}`;getReadOnlyKey=async()=>await fetch(`https://textdb.dev/data/${this.key}`,{method:"GET"}).then((t=>t.text())).then((t=>(t=>{const e=(new DOMParser).parseFromString(t,"text/html").querySelector(".data-api a");if(e){const t=e.href.split("/");return t[t.length-1]}return null})(t)));read=async()=>await fetch(`${TextDB.API_URL}/${this.key}`).then((t=>t.text())).then((t=>t));write=async t=>fetch(`${TextDB.API_URL}/${this.key}`,{body:t,headers:{"Content-Type":"text/plain"},method:"POST"});url=()=>TextDB.API_URL+"/"+this.key;randomKey=(t=3)=>{let e="abcdefghjkmnpqrstuvwxyz",a="";for(let n=0;n<3;n++){for(let n=0;n<t;n++)a+=e[Math.floor(23*Math.random())];n<2&&(a+="-")}return a}}